const header = document.querySelector("#siteHeader");
const menuToggle = document.querySelector("#menuToggle");
const navLinks = document.querySelectorAll(".nav-links a");

if (typeof window.CSS !== "undefined" && typeof window.CSS.registerProperty === "function") {
  document.body.classList.add("registerProperty-supported");
} else {
  document.body.classList.add("registerProperty-not-supported");
}

const revealItems = document.querySelectorAll(
  ".section-reveal, .project-card, .service-card, .archive-card, .contact-card, .gurzil-logo-card, .gurzil-copy-card, .gurzil-image-card, .about-card, .about-skill-pills span, .motion-card"
);
const revealDuration = 800;
const finePointer = window.matchMedia("(pointer: fine) and (hover: hover)").matches;
const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
let scrollIdleTimer;

const markPageScrolling = () => {
  document.body.classList.add("is-scrolling");
  window.clearTimeout(scrollIdleTimer);
  scrollIdleTimer = window.setTimeout(() => {
    document.body.classList.remove("is-scrolling");
  }, 140);
};

const pageLoader = document.querySelector("#pageLoader");
const loaderPercent = document.querySelector("#loaderPercent");
const loaderStatus = document.querySelector("#loaderStatus");
const maximumLoadingTime = 2000;
let contentShown = false;

const showContent = () => {
  if (contentShown) {
    return;
  }

  contentShown = true;
  document.body.classList.remove("is-loading", "loading");
  document.body.classList.add("loaded");

  revealItems.forEach(item => {
    item.classList.add("is-visible");
    if (item.classList.contains("archive-card")) {
      item.classList.add("show");
    }
    item.style.transitionDelay = "";
  });

  document.querySelectorAll("main, .hero, .hero-content, .hero-image, .hero-visual, section, [data-animate], .reveal").forEach(item => {
    item.style.opacity = "1";
    item.style.visibility = "visible";
  });

  if (pageLoader) {
    pageLoader.classList.add("is-hidden", "loaded");
    window.setTimeout(() => {
      pageLoader.style.display = "none";
    }, 700);
  }
};

if (pageLoader && loaderPercent) {
  const loaderDuration = maximumLoadingTime;
  const loaderStatuses = [
    "Designing...",
    "Loading Visuals...",
    "Preparing Portfolio...",
    "Almost Ready..."
  ];
  const startTime = performance.now();
  let activeStatusIndex = 0;

  const updateLoader = currentTime => {
    const elapsed = currentTime - startTime;
    const progress = Math.min(elapsed / loaderDuration, 1);
    const percentage = Math.round(progress * 100);
    const statusIndex = Math.min(Math.floor(progress * loaderStatuses.length), loaderStatuses.length - 1);

    loaderPercent.textContent = `${percentage}%`;

    if (loaderStatus && statusIndex !== activeStatusIndex) {
      activeStatusIndex = statusIndex;
      loaderStatus.classList.add("is-changing");
      window.setTimeout(() => {
        loaderStatus.textContent = loaderStatuses[activeStatusIndex];
        loaderStatus.classList.remove("is-changing");
      }, 140);
    }

    if (progress < 1) {
      requestAnimationFrame(updateLoader);
      return;
    }

    loaderPercent.textContent = "100%";
  };

  requestAnimationFrame(updateLoader);
} else {
  showContent();
}

window.addEventListener("load", () => {
  showContent();
}, { once: true });
window.setTimeout(() => {
  showContent();
}, maximumLoadingTime);

if ("IntersectionObserver" in window) {
  const revealObserver = new IntersectionObserver(
    entries => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          const delay = Number(entry.target.dataset.revealDelay || 0);
          entry.target.classList.add("is-visible");
          if (entry.target.classList.contains("archive-card")) {
            entry.target.classList.add("show");
          }
          window.setTimeout(() => {
            entry.target.style.transitionDelay = "";
          }, revealDuration + delay + 100);
          revealObserver.unobserve(entry.target);
        }
      });
    },
    {
      threshold: 0.14,
      rootMargin: "0px 0px -70px 0px"
    }
  );

  revealItems.forEach((item, index) => {
    const archiveIndex = item.classList.contains("archive-card")
      ? Array.from(document.querySelectorAll(".archive-card")).indexOf(item)
      : -1;
    const delay = archiveIndex >= 0 ? archiveIndex * 70 : Math.min(index * 35, 280);
    item.dataset.revealDelay = String(delay);
    item.style.transitionDelay = `${delay}ms`;
    revealObserver.observe(item);
  });
} else {
  showContent();
}

const updateHeader = () => {
  header.classList.toggle("is-scrolled", window.scrollY > 24);
};

const debounce = (callback, wait = 160) => {
  let timer;

  return (...args) => {
    window.clearTimeout(timer);
    timer = window.setTimeout(() => callback(...args), wait);
  };
};

let headerTicking = false;
const scheduleHeaderUpdate = () => {
  markPageScrolling();

  if (headerTicking) {
    return;
  }

  headerTicking = true;
  requestAnimationFrame(() => {
    updateHeader();
    headerTicking = false;
  });
};

window.addEventListener("scroll", scheduleHeaderUpdate, { passive: true });
window.addEventListener("load", updateHeader);

document.querySelectorAll('a[href^="#"]').forEach(anchor => {
  anchor.addEventListener("click", event => {
    const target = document.querySelector(anchor.getAttribute("href"));

    if (!target) {
      return;
    }

    event.preventDefault();
    target.scrollIntoView({
      behavior: prefersReducedMotion ? "auto" : "smooth",
      block: "start"
    });
  });
});

const motionVideos = document.querySelectorAll(".motion-card video");

if (motionVideos.length && !prefersReducedMotion) {
  const motionObserver = new IntersectionObserver(
    entries => {
      entries.forEach(entry => {
        const video = entry.target;

        if (entry.isIntersecting) {
          video.play().catch(() => {});
          return;
        }

        video.pause();
      });
    },
    {
      rootMargin: "160px 0px",
      threshold: 0.2
    }
  );

  motionVideos.forEach(video => motionObserver.observe(video));
}

const closeMenu = () => {
  header.classList.remove("menu-open");
  document.body.classList.remove("menu-open");
  menuToggle.classList.remove("active");
  const navMenu = document.querySelector(".nav-links");
  navMenu?.classList.remove("open", "active", "is-open");
  menuToggle.setAttribute("aria-expanded", "false");
  menuToggle.setAttribute("aria-label", "Open menu");
};

const sectionLinks = Array.from(navLinks).filter(link => link.hash);
const linkedSections = sectionLinks
  .map(link => document.querySelector(link.hash))
  .filter(Boolean);

const setActiveLink = id => {
  sectionLinks.forEach(link => {
    link.classList.toggle("is-active", link.hash === `#${id}`);
  });
};

if (linkedSections.length) {
  setActiveLink("home");

  const activeSectionObserver = new IntersectionObserver(
    entries => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          setActiveLink(entry.target.id);
        }
      });
    },
    {
      threshold: 0.35,
      rootMargin: "-25% 0px -45% 0px"
    }
  );

  linkedSections.forEach(section => activeSectionObserver.observe(section));
}

const archiveGallery = document.querySelector(".archive-track");
let archiveLightboxClickBlocked = false;
let activeArchiveIndex = 0;
let setActiveArchiveIndex = () => {};

if (archiveGallery) {
  const archivePrev = document.querySelector(".archive-arrow-prev");
  const archiveNext = document.querySelector(".archive-arrow-next");
  const archiveCards = Array.from(archiveGallery.querySelectorAll(".archive-card"));
  let isDraggingArchive = false;
  let dragStartX = 0;
  let dragCurrentX = 0;
  let dragLastX = 0;
  let dragLastTime = 0;
  let dragVelocity = 0;
  let archiveInertiaTimer;
  let archiveWheelFrame = null;
  let archiveWheelDelta = 0;

  const normalizeArchiveIndex = index => (index + archiveCards.length) % archiveCards.length;

  const getArchiveOffset = index => {
    const total = archiveCards.length;
    let offset = index - activeArchiveIndex;
    if (offset > total / 2) {
      offset -= total;
    } else if (offset < -total / 2) {
      offset += total;
    }
    return offset;
  };

  setActiveArchiveIndex = index => {
    if (!archiveCards.length) {
      return;
    }

    activeArchiveIndex = normalizeArchiveIndex(index);
    archiveCards.forEach((card, cardIndex) => {
      const offset = getArchiveOffset(cardIndex);
      const absOffset = Math.abs(offset);
      const direction = Math.sign(offset);
      const isMobileArchive = window.innerWidth <= 640;
      const sideX = isMobileArchive ? 96 : 170;
      const farX = isMobileArchive ? 150 : 275;
      const farStep = isMobileArchive ? 44 : 66;
      const translateX = absOffset === 0
        ? 0
        : direction * (absOffset === 1 ? sideX : farX + (Math.min(absOffset, 4) - 2) * farStep);
      const translateZ = absOffset === 0 ? 120 : absOffset === 1 ? 0 : -160 - (Math.min(absOffset, 4) - 2) * 42;
      const rotateY = absOffset === 0 ? 0 : direction * (absOffset === 1 ? -40 : -65);
      const scale = absOffset === 0 ? 1 : absOffset === 1 ? 0.82 : 0.65;
      const opacity = absOffset === 0 ? 1 : absOffset === 1 ? 0.55 : absOffset <= 4 ? 0.2 : 0;
      const filter = absOffset === 0 ? "brightness(0.96) saturate(0.98) contrast(1.05)" : absOffset === 1 ? "brightness(0.58) saturate(0.86) contrast(1.04)" : "brightness(0.38) saturate(0.76) contrast(1.02)";

      card.style.setProperty("--archive-transform", `translate3d(calc(-50% + ${translateX}px), calc(-50% + var(--archive-float-y, 0px)), ${translateZ}px) rotateY(${rotateY}deg) scale(${scale})`);
      card.style.setProperty("--archive-opacity", String(opacity));
      card.style.setProperty("--archive-filter", filter);
      card.style.setProperty("--archive-z", String(30 - Math.min(absOffset, 8)));
      card.classList.toggle("is-active", offset === 0);
      card.setAttribute("aria-hidden", offset === 0 ? "false" : "true");
    });
  };

  const moveArchive = direction => {
    setActiveArchiveIndex(activeArchiveIndex + direction);
  };

  archiveGallery.addEventListener("wheel", event => {
    event.preventDefault();
    const delta = Math.abs(event.deltaY) >= Math.abs(event.deltaX) ? event.deltaY : event.deltaX;
    archiveWheelDelta += delta;

    if (!archiveWheelFrame) {
      archiveWheelFrame = requestAnimationFrame(() => {
        if (Math.abs(archiveWheelDelta) > 18) {
          moveArchive(archiveWheelDelta > 0 ? 1 : -1);
        }
        archiveWheelDelta = 0;
        archiveWheelFrame = null;
      });
    }
  }, { passive: false });

  archiveGallery.addEventListener("pointerdown", event => {
    window.clearTimeout(archiveInertiaTimer);
    isDraggingArchive = true;
    archiveLightboxClickBlocked = false;
    dragStartX = event.clientX;
    dragCurrentX = event.clientX;
    dragLastX = event.clientX;
    dragLastTime = performance.now();
    dragVelocity = 0;
    archiveGallery.classList.add("is-dragging");
    archiveGallery.setPointerCapture(event.pointerId);
  });

  archiveGallery.addEventListener("pointermove", event => {
    if (!isDraggingArchive) {
      return;
    }

    const dragDistance = event.clientX - dragStartX;
    const now = performance.now();
    const elapsed = Math.max(1, now - dragLastTime);
    dragVelocity = (event.clientX - dragLastX) / elapsed;
    dragCurrentX = event.clientX;
    dragLastX = event.clientX;
    dragLastTime = now;
    if (Math.abs(dragDistance) > 8) {
      archiveLightboxClickBlocked = true;
    }
  });

  const stopArchiveDrag = event => {
    if (!isDraggingArchive) {
      return;
    }

    isDraggingArchive = false;
    archiveGallery.classList.remove("is-dragging");
    const dragDistance = dragCurrentX - dragStartX;

    if (Math.abs(dragDistance) > 42) {
      const direction = dragDistance < 0 ? 1 : -1;
      moveArchive(direction);

      if (Math.abs(dragVelocity) > 0.85 || Math.abs(dragDistance) > 160) {
        archiveInertiaTimer = window.setTimeout(() => moveArchive(direction), 190);
      }
    }

    if (archiveGallery.hasPointerCapture(event.pointerId)) {
      archiveGallery.releasePointerCapture(event.pointerId);
    }

    window.setTimeout(() => {
      archiveLightboxClickBlocked = false;
    }, 0);
  };

  archiveGallery.addEventListener("pointerup", stopArchiveDrag);
  archiveGallery.addEventListener("pointercancel", stopArchiveDrag);
  archiveGallery.addEventListener("pointerleave", stopArchiveDrag);
  archivePrev?.addEventListener("click", () => moveArchive(-1));
  archiveNext?.addEventListener("click", () => moveArchive(1));
  window.addEventListener("keydown", event => {
    const lightboxOpen = document.body.classList.contains("archive-lightbox-open");
    if (lightboxOpen) {
      return;
    }

    if (event.key === "ArrowLeft") {
      event.preventDefault();
      moveArchive(-1);
    } else if (event.key === "ArrowRight") {
      event.preventDefault();
      moveArchive(1);
    }
  });
  window.addEventListener("resize", debounce(() => setActiveArchiveIndex(activeArchiveIndex)), { passive: true });
  setActiveArchiveIndex(0);
}

const archiveLightboxImages = document.querySelectorAll(".creative-collection .archive-card .showcase-card-image");

if (archiveLightboxImages.length) {
  const archiveLightboxItems = Array.from(archiveLightboxImages);
  let activeArchiveLightboxIndex = 0;
  let archiveLightboxCloseTimer;
  const archiveLightbox = document.createElement("div");
  archiveLightbox.className = "archive-lightbox";
  archiveLightbox.setAttribute("role", "dialog");
  archiveLightbox.setAttribute("aria-modal", "true");
  archiveLightbox.setAttribute("aria-label", "Design Archive image preview");
  archiveLightbox.innerHTML = `
    <button class="archive-lightbox-close" type="button" aria-label="Close image preview">X</button>
    <button class="archive-lightbox-nav archive-lightbox-prev" type="button" aria-label="Previous image">&larr;</button>
    <img class="archive-lightbox-image" alt="" />
    <button class="archive-lightbox-nav archive-lightbox-next" type="button" aria-label="Next image">&rarr;</button>
  `;
  document.body.appendChild(archiveLightbox);

  const archiveLightboxImage = archiveLightbox.querySelector(".archive-lightbox-image");
  const archiveLightboxClose = archiveLightbox.querySelector(".archive-lightbox-close");
  const archiveLightboxPrev = archiveLightbox.querySelector(".archive-lightbox-prev");
  const archiveLightboxNext = archiveLightbox.querySelector(".archive-lightbox-next");

  const setArchiveLightboxImage = index => {
    activeArchiveLightboxIndex = (index + archiveLightboxItems.length) % archiveLightboxItems.length;
    const image = archiveLightboxItems[activeArchiveLightboxIndex];
    archiveLightboxImage.src = image.getAttribute("src");
    archiveLightboxImage.alt = image.alt || "Design Archive artwork preview";
  };

  const closeArchiveLightbox = () => {
    window.clearTimeout(archiveLightboxCloseTimer);
    archiveLightbox.classList.remove("is-open");
    document.body.classList.remove("archive-lightbox-open");
    archiveLightboxCloseTimer = window.setTimeout(() => {
      if (!archiveLightbox.classList.contains("is-open")) {
        archiveLightboxImage.removeAttribute("src");
        archiveLightboxImage.alt = "";
      }
    }, 250);
  };

  const openArchiveLightbox = index => {
    window.clearTimeout(archiveLightboxCloseTimer);
    setArchiveLightboxImage(index);
    document.body.classList.add("archive-lightbox-open");
    archiveLightbox.classList.add("is-open");
    archiveLightboxClose.focus({ preventScroll: true });
  };

  const showArchiveLightboxImage = direction => {
    setArchiveLightboxImage(activeArchiveLightboxIndex + direction);
  };

  archiveLightboxItems.forEach((image, index) => {
    image.addEventListener("click", event => {
      event.stopPropagation();
      if (archiveLightboxClickBlocked) {
        return;
      }

      if (index !== activeArchiveIndex) {
        setActiveArchiveIndex(index);
        return;
      }

      openArchiveLightbox(index);
    });
  });

  archiveLightboxClose.addEventListener("click", closeArchiveLightbox);
  archiveLightboxPrev.addEventListener("click", event => {
    event.stopPropagation();
    showArchiveLightboxImage(-1);
  });
  archiveLightboxNext.addEventListener("click", event => {
    event.stopPropagation();
    showArchiveLightboxImage(1);
  });

  archiveLightbox.addEventListener("click", event => {
    if (event.target === archiveLightbox) {
      closeArchiveLightbox();
    }
  });

  window.addEventListener("keydown", event => {
    if (!archiveLightbox.classList.contains("is-open")) {
      return;
    }

    if (event.key === "Escape") {
      event.preventDefault();
      closeArchiveLightbox();
    } else if (event.key === "ArrowLeft") {
      event.preventDefault();
      showArchiveLightboxImage(-1);
    } else if (event.key === "ArrowRight") {
      event.preventDefault();
      showArchiveLightboxImage(1);
    }
  });
}

menuToggle.addEventListener("click", () => {
  if (window.innerWidth <= 768) {
    closeMenu();
    return;
  }

  const isOpen = header.classList.toggle("menu-open");
  document.body.classList.toggle("menu-open", isOpen);
  menuToggle.classList.toggle("active", isOpen);
  const navMenu = document.querySelector(".nav-links");
  navMenu?.classList.toggle("open", isOpen);
  navMenu?.classList.toggle("active", isOpen);
  navMenu?.classList.toggle("is-open", isOpen);
  menuToggle.setAttribute("aria-expanded", String(isOpen));
  menuToggle.setAttribute("aria-label", isOpen ? "Close menu" : "Open menu");
});

navLinks.forEach(link => {
  link.addEventListener("click", () => {
    if (link.hash) {
      setActiveLink(link.hash.slice(1));
    }

    closeMenu();
  });
});

window.addEventListener("resize", debounce(() => {
  if (window.innerWidth > 820 || window.innerWidth <= 768) {
    closeMenu();
  }
}), { passive: true });

if (window.innerWidth <= 768) {
  closeMenu();
}

window.addEventListener("keydown", event => {
  if (event.key === "Escape") {
    closeMenu();
  }
});
